import os
import cv2
import numpy as np
from face_recognition import FaceRecognizer, load_image_file, face_encodings

def create_face_encoder(images_folder):
    known_faces = {}
    for subdir, dirs, files in os.walk(images_folder):
        for file in files:
            if file.endswith(".jpg") or file.endswith(".png"):
                image = load_image_file(os.path.join(subdir, file))
                face_encoding = face_encodings(image)[0]
                known_faces[os.path.relpath(os.path.join(subdir, file)).replace("\\", "/")] = face_encoding
    return known_faces

def train_model(known_faces, model_filename):
    model = FaceRecognizer()
    model.train(known_faces, np.array([i for i in range(len(known_faces))]))
    model.save(model_filename)

def recognize_faces(image, known_faces, model_filename):
    face_encodings = face_encodings(image)
    results = []
    for face_encoding, name in known_faces.items():
        matches = model.predict([face_encoding])
        confidence = matches[0][1]
        results.append((confidence, name))
    return sorted(results, key=lambda x: x[0], reverse=True)

def main():
    images_folder = 'employee_photos'
    model_filename = 'face_recognition_model.pickle'

    if not os.path.exists(model_filename):
        known_faces = create_face_encoder(images_folder)
        train_model(known_faces, model_filename)

    face_recognition_model = FaceRecognizer.load(model_filename)
    image = load_image_file('test_image.jpg')
    results = recognize_faces(image, known_faces, model_filename)

    for confidence, name in results:
        print(f"{name}: {confidence}")

if __name__ == "__main__":
    main()